export enum UserRole {
  DRIVER = 'driver',
  STUDENT = 'student'
}

export interface User {
  uid: string;
  name: string;
  role: UserRole;
  busId?: string;
}

export interface BusLocation {
  lat: number;
  lng: number;
  updatedAt: number;
  status: 'running' | 'stopped' | 'idle';
  busId: string;
  driverName: string;
}

export interface Message {
  id: string;
  text: string;
  sender: 'system' | 'ai' | 'user';
  timestamp: number;
}

import { BusLocation } from '../types';

/**
 * In a real production environment, this would be Firebase Realtime Database.
 * For this demo, we use BroadcastChannel to allow the "Driver" tab to update
 * the "Student" tab in real-time within the same browser session.
 */
const DB_CHANNEL = new BroadcastChannel('bus_tracking_channel');

type Listener = (location: BusLocation) => void;
const listeners: Set<Listener> = new Set();

DB_CHANNEL.onmessage = (event) => {
  if (event.data && event.data.type === 'BUS_UPDATE') {
    listeners.forEach((fn) => fn(event.data.payload));
  }
};

export const updateBusLocation = (location: BusLocation) => {
  DB_CHANNEL.postMessage({
    type: 'BUS_UPDATE',
    payload: location
  });
};

export const subscribeToBus = (busId: string, callback: Listener) => {
  listeners.add(callback);
  return () => {
    listeners.delete(callback);
  };
};

export const MOCK_USERS = [
  { uid: 'u1', name: 'Arun (Driver)', role: 'driver', busId: 'bus-01' },
  { uid: 'u2', name: 'Student 1', role: 'student' }
];

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const getBusInsights = async (location: { lat: number, lng: number }, trafficStatus: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `The bus is currently at coordinates (${location.lat}, ${location.lng}). 
                 Traffic status is ${trafficStatus}. 
                 Provide a 1-sentence helpful status update for students waiting for this college bus.`,
      config: {
        temperature: 0.7,
        maxOutputTokens: 100,
      }
    });
    return response.text || "Tracking active. No specific alerts.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Status active. Connectivity issues with AI insights.";
  }
};

