export default LoginScreen;

import React, { useState, useEffect, useRef } from 'react';
import { User, BusLocation } from '../types';
import { updateBusLocation } from '../services/mockDatabase';
import Layout from '../components/Layout';

interface DriverScreenProps {
  user: User;
  onLogout: () => void;
}

const DriverScreen: React.FC<DriverScreenProps> = ({ user, onLogout }) => {
  const [isTracking, setIsTracking] = useState(false);
  const [currentLocation, setCurrentLocation] = useState<BusLocation | null>(null);
  const watchId = useRef<number | null>(null);

  const startTracking = () => {
    if (!navigator.geolocation) {
      alert("Geolocation is not supported by your browser.");
      return;
    }

    setIsTracking(true);
    watchId.current = navigator.geolocation.watchPosition(
      (position) => {
        const newLocation: BusLocation = {
          lat: position.coords.latitude,
          lng: position.coords.longitude,
          updatedAt: Date.now(),
          status: 'running',
          busId: user.busId || 'bus-default',
          driverName: user.name
        };
        setCurrentLocation(newLocation);
        updateBusLocation(newLocation);
      },
      (error) => {
        console.error("GPS Error:", error);
        setIsTracking(false);
      },
      { enableHighAccuracy: true, distanceFilter: 10 }
    );
  };

  const stopTracking = () => {
    if (watchId.current !== null) {
      navigator.geolocation.clearWatch(watchId.current);
      watchId.current = null;
    }
    setIsTracking(false);
    if (currentLocation) {
      updateBusLocation({ ...currentLocation, status: 'stopped', updatedAt: Date.now() });
    }
  };

  useEffect(() => {
    return () => {
      if (watchId.current !== null) {
        navigator.geolocation.clearWatch(watchId.current);
      }
    };
  }, []);

  return (
    <Layout title="Driver Dashboard" onLogout={onLogout} userName={user.name}>
      <div className="max-w-4xl mx-auto p-4 sm:p-6 lg:p-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <h3 className="text-xl font-bold text-slate-800 mb-4">Bus Controls</h3>
            <p className="text-slate-500 mb-6 leading-relaxed">
              Start broadcasting your location to students. Ensure your GPS is enabled and you have a stable internet connection.
            </p>

            <div className="space-y-4">
              <button
                onClick={isTracking ? stopTracking : startTracking}
                className={`w-full py-4 rounded-xl font-bold text-lg shadow-md transition-all duration-300 flex items-center justify-center space-x-3 ${
                  isTracking 
                    ? 'bg-red-500 hover:bg-red-600 text-white' 
                    : 'bg-indigo-600 hover:bg-indigo-700 text-white'
                }`}
              >
                {isTracking ? (
                  <>
                    <svg className="w-6 h-6 animate-pulse" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 10a1 1 0 011-1h4a1 1 0 011 1v4a1 1 0 01-1 1H10a1 1 0 01-1-1v-4z" />
                    </svg>
                    <span>Stop Tracking</span>
                  </>
                ) : (
                  <>
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
                    </svg>
                    <span>Start Tracking</span>
                  </>
                )}
              </button>
            </div>
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <h3 className="text-xl font-bold text-slate-800 mb-4">Live Stats</h3>
            <div className="space-y-4">
              <div className="flex justify-between items-center p-3 bg-slate-50 rounded-lg">
                <span className="text-slate-500">Status:</span>
                <span className={`px-2 py-1 rounded text-xs font-bold uppercase ${isTracking ? 'bg-green-100 text-green-700' : 'bg-slate-200 text-slate-600'}`}>
                  {isTracking ? 'Transmitting' : 'Offline'}
                </span>
              </div>
              <div className="flex justify-between items-center p-3 bg-slate-50 rounded-lg">
                <span className="text-slate-500">Bus ID:</span>
                <span className="font-semibold text-slate-700">{user.busId}</span>
              </div>
              <div className="flex justify-between items-center p-3 bg-slate-50 rounded-lg">
                <span className="text-slate-500">Last Coordinate:</span>
                <span className="text-xs font-mono text-slate-600">
                  {currentLocation ? `${currentLocation.lat.toFixed(4)}, ${currentLocation.lng.toFixed(4)}` : 'N/A'}
                </span>
              </div>
            </div>
          </div>
        </div>

        <div className="mt-8 bg-indigo-50 border border-indigo-100 rounded-2xl p-6">
          <h4 className="flex items-center text-indigo-800 font-bold mb-3">
            <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
            Driver Safety Reminder
          </h4>
          <ul className="text-indigo-700 text-sm space-y-2 list-disc list-inside">
            <li>Keep the phone mounted on the dashboard at all times.</li>
            <li>Connect your device to a charger for long routes.</li>
            <li>Do not interact with the screen while the vehicle is in motion.</li>
            <li>Ensure the UniTrack app remains in the foreground for best GPS accuracy.</li>
          </ul>
        </div>
      </div>
    </Layout>
  );
};

export default DriverScreen;

import React, { useState, useEffect } from 'react';
import { User, BusLocation } from '../types';
import { subscribeToBus } from '../services/mockDatabase';
import { getBusInsights } from '../services/geminiService';
import Layout from '../components/Layout';
import MapComponent from '../components/MapComponent';

interface StudentScreenProps {
  user: User;
  onLogout: () => void;
}

const StudentScreen: React.FC<StudentScreenProps> = ({ user, onLogout }) => {
  const [busLocation, setBusLocation] = useState<BusLocation | null>(null);
  const [aiStatus, setAiStatus] = useState<string>("Waiting for live updates...");
  const [lastUpdateText, setLastUpdateText] = useState<string>("Never");

  useEffect(() => {
    const unsubscribe = subscribeToBus('bus-01', (location) => {
      setBusLocation(location);
      setLastUpdateText(new Date(location.updatedAt).toLocaleTimeString());
    });

    return () => unsubscribe();
  }, []);

  useEffect(() => {
    if (busLocation && busLocation.status === 'running') {
      const fetchAiInsight = async () => {
        const insight = await getBusInsights({ lat: busLocation.lat, lng: busLocation.lng }, "Normal Flow");
        setAiStatus(insight);
      };

      // Update AI insights every 30 seconds to manage API quota
      const interval = setInterval(fetchAiInsight, 30000);
      fetchAiInsight();
      return () => clearInterval(interval);
    } else {
      setAiStatus("Bus is currently idle or offline.");
    }
  }, [busLocation?.status]);

  return (
    <Layout title="UniTrack Map" onLogout={onLogout} userName={user.name}>
      <div className="flex flex-col h-[calc(100vh-4rem)]">
        {/* Map Area */}
        <div className="flex-1 relative">
          <MapComponent location={busLocation} />

          {/* Overlay Status Bar */}
          <div className="absolute bottom-6 left-1/2 transform -translate-x-1/2 w-[90%] max-w-xl">
            <div className="bg-white rounded-2xl shadow-2xl border border-slate-200 p-4 flex items-center space-x-4">
              <div className={`w-3 h-3 rounded-full animate-ping ${busLocation?.status === 'running' ? 'bg-green-500' : 'bg-red-500'}`} />
              <div className="flex-1 overflow-hidden">
                <p className="text-xs font-bold text-slate-400 uppercase tracking-tighter">Live Insight</p>
                <p className="text-slate-700 font-medium text-sm truncate">{aiStatus}</p>
              </div>
              <div className="text-right border-l pl-4 border-slate-100">
                <p className="text-xs text-slate-400 font-bold uppercase">Updated</p>
                <p className="text-slate-700 font-bold text-sm whitespace-nowrap">{lastUpdateText}</p>
              </div>
            </div>
          </div>
        </div>

        {/* Info Panel for Desktop/Tablet */}
        <div className="hidden lg:block w-80 absolute top-20 right-6 bg-white/95 backdrop-blur-sm rounded-2xl shadow-xl border border-slate-200 p-6">
          <h3 className="text-lg font-bold text-slate-800 mb-4">Bus Information</h3>
          <div className="space-y-6">
            <div className="flex items-start space-x-3">
              <div className="bg-indigo-100 p-2 rounded-lg">
                <svg className="w-5 h-5 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                </svg>
              </div>
              <div>
                <p className="text-xs text-slate-400 font-bold">Driver</p>
                <p className="text-slate-800 font-semibold">{busLocation?.driverName || 'Finding driver...'}</p>
              </div>
            </div>

            <div className="flex items-start space-x-3">
              <div className="bg-emerald-100 p-2 rounded-lg">
                <svg className="w-5 h-5 text-emerald-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
              </div>
              <div>
                <p className="text-xs text-slate-400 font-bold">Registration</p>
                <p className="text-slate-800 font-semibold">{busLocation?.busId || 'Bus-01'}</p>
              </div>
            </div>

            <div className="pt-4 border-t border-slate-100">
              <p className="text-xs text-slate-500 italic">"Safe travels to your destination! UniTrack estimates normal arrival times today."</p>
            </div>
          </div>
        </div>
      </div>
    </Layout>
  );
};

export default StudentScreen;

import React, { useState, useEffect } from 'react';
import { User, UserRole } from './types';
import LoginScreen from './screens/LoginScreen';
import DriverScreen from './screens/DriverScreen';
import StudentScreen from './screens/StudentScreen';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isInitializing, setIsInitializing] = useState(true);

  useEffect(() => {
    // Check local storage for persistent session
    const savedUser = localStorage.getItem('unitrack_user');
    if (savedUser) {
      setCurrentUser(JSON.parse(savedUser));
    }
    setIsInitializing(false);
  }, []);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('unitrack_user', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('unitrack_user');
  };

  if (isInitializing) {
    return (
      <div className="min-h-screen bg-indigo-600 flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-4 border-white border-t-transparent"></div>
      </div>
    );
  }

  if (!currentUser) {
    return <LoginScreen onLogin={handleLogin} />;
  }

  return (
    <>
      {currentUser.role === UserRole.DRIVER ? (
        <DriverScreen user={currentUser} onLogout={handleLogout} />
      ) : (
        <StudentScreen user={currentUser} onLogout={handleLogout} />
      )}
    </>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";

