  const googleMap = useRef<any>(null);
  const marker = useRef<any>(null);

  useEffect(() => {
    if (mapRef.current && !googleMap.current) {
      const initialPos = location ? { lat: location.lat, lng: location.lng } : { lat: 12.9716, lng: 77.5946 };

      // Fix: Access google through window and cast to any to fix "Cannot find name 'google'"
      const g = (window as any).google;
      if (!g || !g.maps) return;

      googleMap.current = new g.maps.Map(mapRef.current, {
        center: initialPos,
        zoom: zoom,
        styles: [
          {
            "featureType": "poi",
            "elementType": "labels",
            "stylers": [{ "visibility": "off" }]
          }
        ],
        disableDefaultUI: false,
        zoomControl: true,
      });

      marker.current = new g.maps.Marker({
        position: initialPos,
        map: googleMap.current,
        title: "College Bus",
        icon: {
          path: "M18.8,3.5C18.1,2.6,17,2,15.8,2H8.2C7,2,5.9,2.6,5.2,3.5C4.5,4.4,4,5.7,4,7v10c0,1.1,0.9,2,2,2h1v2c0,0.6,0.4,1,1,1h1 c0.6,0,1-0.4,1-1v-2h6v2c0,0.6,0.4,1,1,1h1c0.6,0,1-0.4,1-1v-2h1c1.1,0,2-0.9,2-2V7C20,5.7,19.5,4.4,18.8,3.5z M9,17 c-0.6,0-1-0.4-1-1s0.4-1,1-1s1,0.4,1,1S9.6,17,9,17z M15,17c-0.6,0-1-0.4-1-1s0.4-1,1-1s1,0.4,1,1S15.6,17,15,17z M18,12H6V6h12V12z",
          fillColor: "#4F46E5",
          fillOpacity: 1,
          strokeWeight: 1,
          strokeColor: "#ffffff",
          scale: 1.5,
          anchor: new g.maps.Point(12, 12),
        }
      });
    }
  }, []);

  useEffect(() => {
    if (location && marker.current && googleMap.current) {
      const newPos = { lat: location.lat, lng: location.lng };
      marker.current.setPosition(newPos);
      googleMap.current.panTo(newPos);
