interface DriverScreenProps {
  user: User;
  onLogout: () => void;
}

const DriverScreen: React.FC<DriverScreenProps> = ({ user, onLogout }) => {
  const [isTracking, setIsTracking] = useState(false);
  const [currentLocation, setCurrentLocation] = useState<BusLocation | null>(null);
  const watchId = useRef<number | null>(null);

  const startTracking = () => {
    if (!navigator.geolocation) {
      alert("Geolocation is not supported by your browser.");
      return;
    }

    setIsTracking(true);
    watchId.current = navigator.geolocation.watchPosition(
      (position) => {
        const newLocation: BusLocation = {
          lat: position.coords.latitude,
          lng: position.coords.longitude,
          updatedAt: Date.now(),
          status: 'running',
          busId: user.busId || 'bus-default',
          driverName: user.name
        };
        setCurrentLocation(newLocation);
        updateBusLocation(newLocation);
      },
      (error) => {
        console.error("GPS Error:", error);
        setIsTracking(false);
      },
      // Fix: Removed 'distanceFilter' as it is not a valid property of PositionOptions in standard Geolocation API
      { enableHighAccuracy: true }
    );
  };

  const stopTracking = () => {
    if (watchId.current !== null) {
      navigator.geolocation.clearWatch(watchId.current);
      watchId.current = null;
    }
    setIsTracking(false);
    if (currentLocation) {
      updateBusLocation({ ...currentLocation, status: 'stopped', updatedAt: Date.now() });
    }
  };

  useEffect(() => {
    return () => {
      if (watchId.current !== null) {
        navigator.geolocation.clearWatch(watchId.current);
      }
    };
  }, []);

  return (
    <Layout title="Driver Dashboard" onLogout={onLogout} userName={user.name}>
      <div className="max-w-4xl mx-auto p-4 sm:p-6 lg:p-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <h3 className="text-xl font-bold text-slate-800 mb-4">Bus Controls</h3>
            <p className="text-slate-500 mb-6 leading-relaxed">
              Start broadcasting your location to students. Ensure your GPS is enabled and you have a stable internet connection.
            </p>

            <div className="space-y-4">
              <button
                onClick={isTracking ? stopTracking : startTracking}
                className={`w-full py-4 rounded-xl font-bold text-lg shadow-md transition-all duration-300 flex items-center justify-center space-x-3 ${
                  isTracking 
                    ? 'bg-red-500 hover:bg-red-600 text-white' 
                    : 'bg-indigo-600 hover:bg-indigo-700 text-white'
                }`}
              >
                {isTracking ? (
                  <>
                    <svg className="w-6 h-6 animate-pulse" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 10a1 1 0 011-1h4a1 1 0 011 1v4a1 1 0 01-1 1H10a1 1 0 01-1-1v-4z" />
                    </svg>
                    <span>Stop Tracking</span>
                  </>
                ) : (
                  <>
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
                    </svg>
                    <span>Start Tracking</span>
                  </>
                )}
              </button>
            </div>
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <h3 className="text-xl font-bold text-slate-800 mb-4">Live Stats</h3>
            <div className="space-y-4">
