import React, { useEffect, useRef, useState } from 'react';
import { BusLocation } from '../types';

interface MapComponentProps {
  location: BusLocation | null;
  zoom?: number;
}

const MapComponent: React.FC<MapComponentProps> = ({ location, zoom = 15 }) => {
  const mapRef = useRef<HTMLDivElement>(null);
  const googleMap = useRef<any>(null);
  const marker = useRef<any>(null);
  const [isLoaded, setIsLoaded] = useState(false);
  const [loadError, setLoadError] = useState(false);

  useEffect(() => {
    // Check if Google Maps is already loaded
    if ((window as any).google && (window as any).google.maps) {
      setIsLoaded(true);
      return;
    }

    // Dynamic Script Loader
    const script = document.createElement('script');
    const apiKey = process.env.API_KEY || '';
    script.src = `https://maps.googleapis.com/maps/api/js?key=${apiKey}&libraries=places`;
    script.async = true;
    script.defer = true;

    script.onload = () => {
      setIsLoaded(true);
    };

    script.onerror = () => {
      console.error("Failed to load Google Maps API");
      setLoadError(true);
    };

    document.head.appendChild(script);

    return () => {
      // Optional: Cleanup if needed, though usually Maps stays loaded
    };
  }, []);

  useEffect(() => {
    if (isLoaded && mapRef.current && !googleMap.current) {
      const g = (window as any).google;
      const initialPos = location ? { lat: location.lat, lng: location.lng } : { lat: 12.9716, lng: 77.5946 };

      googleMap.current = new g.maps.Map(mapRef.current, {
        center: initialPos,
        zoom: zoom,
        styles: [
          {
            "featureType": "poi",
            "elementType": "labels",
            "stylers": [{ "visibility": "off" }]
          }
        ],
        disableDefaultUI: false,
        zoomControl: true,
        mapTypeControl: false,
        streetViewControl: false,
        fullscreenControl: false
      });

      marker.current = new g.maps.Marker({
        position: initialPos,
        map: googleMap.current,
        title: "College Bus",
        icon: {
          path: "M18.8,3.5C18.1,2.6,17,2,15.8,2H8.2C7,2,5.9,2.6,5.2,3.5C4.5,4.4,4,5.7,4,7v10c0,1.1,0.9,2,2,2h1v2c0,0.6,0.4,1,1,1h1 c0.6,0,1-0.4,1-1v-2h6v2c0,0.6,0.4,1,1,1h1c0.6,0,1-0.4,1-1v-2h1c1.1,0,2-0.9,2-2V7C20,5.7,19.5,4.4,18.8,3.5z M9,17 c-0.6,0-1-0.4-1-1s0.4-1,1-1s1,0.4,1,1S9.6,17,9,17z M15,17c-0.6,0-1-0.4-1-1s0.4-1,1-1s1,0.4,1,1S15.6,17,15,17z M18,12H6V6h12V12z",
          fillColor: "#4F46E5",
          fillOpacity: 1,
          strokeWeight: 1,
          strokeColor: "#ffffff",
          scale: 1.5,
          anchor: new g.maps.Point(12, 12),
        }
      });
    }
  }, [isLoaded]);

  useEffect(() => {
    if (location && marker.current && googleMap.current) {
      const newPos = { lat: location.lat, lng: location.lng };
      marker.current.setPosition(newPos);
      googleMap.current.panTo(newPos);
    }
  }, [location]);

  if (loadError) {
    return (
      <div className="w-full h-full flex items-center justify-center bg-slate-100 rounded-xl border border-slate-200 p-8 text-center">
        <div>
          <svg className="w-12 h-12 text-slate-400 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
          </svg>
          <p className="text-slate-600 font-bold">Map Loading Error</p>
          <p className="text-slate-400 text-sm mt-1">Please ensure your API key is correctly configured.</p>
        </div>
      </div>
    );
  }

  if (!isLoaded) {
    return (
      <div className="w-full h-full flex items-center justify-center bg-slate-100 rounded-xl border border-slate-200">
        <div className="flex flex-col items-center">
          <div className="w-8 h-8 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-3"></div>
          <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Initializing Map...</span>
        </div>
      </div>
    );
  }

  return <div ref={mapRef} className="w-full h-full rounded-xl overflow-hidden shadow-inner border border-slate-200" />;
};

